  ('elementary-64311456-moex-00522', 'elementary-64311456', 'elementary-64311456-moex-112-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '在老年議題中，我們提倡老人從事任何生產財貨或無酬的活動，增進社會的貢獻，請問是指下列那一項？', '["健康老化", "生產性老化", "活力老化", "在地老化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "e8d72e9f85c4", "answer_pdf_sha1": "83986d7ed3c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
