  ('elementary-64311456-moex-00524', 'elementary-64311456', 'elementary-64311456-moex-112-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '「兒童若具有主見能力，應能對影響其本人的一切事務自由表達意見，對其意見應按兒童的年齡和成熟 程度給予適當的看待」，請問以上所陳述的是《兒童權利公約》的那一項原則？', '["禁止差別待遇", "兒童最佳利益", "生存與發展權", "意見表達及參與權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "e8d72e9f85c4", "answer_pdf_sha1": "83986d7ed3c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
